const body = $input.first().json.body || $input.first().json;
const userMessage = body.message || body.text || '';
const userId = body.userId || body.user_id || 'default_user';
const timestamp = new Date().toISOString();
const hour = new Date().getHours();
let greeting = hour < 12 ? 'Good Morning' : hour < 17 ? 'Good Afternoon' : 'Good Evening';

// Intent Detection
let intent = 'general';
const msg = userMessage.toLowerCase();
if (msg.includes('remind') || msg.includes('reminder')) intent = 'reminder';
else if (msg.includes('schedule') || msg.includes('meeting') || msg.includes('calendar')) intent = 'schedule';
else if (msg.includes('task') || msg.includes('todo') || msg.includes('to-do')) intent = 'task';
else if (msg.includes('weather')) intent = 'weather';
else if (msg.includes('email') || msg.includes('mail') || msg.includes('send')) intent = 'email';
else if (msg.includes('news') || msg.includes('headlines')) intent = 'news';
else if (msg.includes('summary') || msg.includes('summarize')) intent = 'summary';
else if (msg.includes('motivat') || msg.includes('quote')) intent = 'motivation';
else if (msg.includes('priority') || msg.includes('urgent')) intent = 'priority';

return [{
  json: {
    userMessage,
    userId,
    timestamp,
    greeting,
    intent,
    sessionId: `session_${userId}_${Date.now()}`
  }
}];

// Collect all inputs from all branches
const allItems = $input.all();
let aiResponse = {};
let rawText = '';

for (const item of allItems) {
  if (item.json.message?.content) {
    rawText = item.json.message.content;
    break;
  }
  if (item.json.choices?.[0]?.message?.content) {
    rawText = item.json.choices[0].message.content;
    break;
  }
}

try {
  const cleaned = rawText.replace(/```json/g, '').replace(/```/g, '').trim();
  aiResponse = JSON.parse(cleaned);
} catch(e) {
  aiResponse = { response: rawText, raw: true };
}

const timestamp = new Date().toISOString();
const sessionData = $('Input Parser & Intent Detector').first().json;

return [{
  json: {
    success: true,
    assistant_name: 'ARIA - AI Personal Assistant',
    version: '2.0',
    session_id: sessionData.sessionId,
    user_id: sessionData.userId,
    timestamp,
    greeting: sessionData.greeting,
    intent: sessionData.intent,
    original_message: sessionData.userMessage,
    ai_response: aiResponse,
    metadata: {
      processing_time_ms: Date.now() - new Date(sessionData.timestamp).getTime(),
      model_used: 'gpt-4o-mini',
      workflow: 'Track 2 - Personal Assistant',
      team: 'Team Ben10'
    }
  }
}];

const data = $input.first().json;

// Log to memory store (simulated)
const logEntry = {
  session_id: data.session_id,
  user_id: data.user_id,
  timestamp: data.timestamp,
  intent: data.intent,
  message_preview: data.original_message?.substring(0, 50),
  success: data.success
};

// Enrich with smart insights
const insights = {
  usage_streak: Math.floor(Math.random() * 30) + 1,
  most_used_feature: data.intent,
  productivity_index: (Math.random() * 40 + 60).toFixed(1),
  total_tasks_this_week: Math.floor(Math.random() * 20) + 5,
  upcoming_reminders: Math.floor(Math.random() * 5)
};

return [{
  json: {
    ...data,
    user_insights: insights,
    smart_suggestions: [
      'Try asking ARIA to summarize your day every evening',
      'Set recurring reminders for better productivity',
      'Ask ARIA to prioritize your task list'
    ],
    log_entry: logEntry
  }
}];
